import { useState, useRef, useCallback, useEffect } from 'react';

const ICE_CONFIG = {
  iceServers: [
    {
      urls: process.env.REACT_APP_TURN_URL || 'turn:107.180.75.184:3000',
      username: process.env.REACT_APP_TURN_USERNAME || 'rearguard',
      credential: process.env.REACT_APP_TURN_PASSWORD || '123456',
    },
  ],
};

const useWebRTC = () => {
  const [localStream, setLocalStream] = useState(null);
  const [remoteStream, setRemoteStream] = useState(null);
  const [connectionState, setConnectionState] = useState('new');
  const pcRef = useRef(null);

  const createPeerConnection = useCallback(() => {
    if (pcRef.current) {
      pcRef.current.close();
    }
    const pc = new RTCPeerConnection(ICE_CONFIG);

    pc.oniceconnectionstatechange = () => {
      setConnectionState(pc.iceConnectionState);
    };

    pc.ontrack = (event) => {
      if (event.streams && event.streams[0]) {
        setRemoteStream(event.streams[0]);
      }
    };

    pcRef.current = pc;
    return pc;
  }, []);

  const startLocalStream = useCallback(async (callType = 'video') => {
    try {
      const constraints = {
        audio: true,
        video: callType === 'video' ? {
          width: { ideal: 640 },
          height: { ideal: 480 },
          frameRate: { ideal: 30 },
          facingMode: 'user',
        } : false,
      };
      const stream = await navigator.mediaDevices.getUserMedia(constraints);
      setLocalStream(stream);
      return stream;
    } catch (error) {
      console.error('Failed to get local media:', error);
      throw error;
    }
  }, []);

  const addLocalStreamToPeer = useCallback((stream) => {
    const pc = pcRef.current;
    if (!pc || !stream) return;
    stream.getTracks().forEach((track) => {
      pc.addTrack(track, stream);
    });
  }, []);

  const createOffer = useCallback(async () => {
    const pc = pcRef.current;
    if (!pc) return null;
    const offer = await pc.createOffer({
      offerToReceiveAudio: true,
      offerToReceiveVideo: true,
    });
    await pc.setLocalDescription(offer);
    return offer;
  }, []);

  const createAnswer = useCallback(async () => {
    const pc = pcRef.current;
    if (!pc) return null;
    const answer = await pc.createAnswer();
    await pc.setLocalDescription(answer);
    return answer;
  }, []);

  const setRemoteDescription = useCallback(async (sdp) => {
    const pc = pcRef.current;
    if (!pc) return;
    await pc.setRemoteDescription(new RTCSessionDescription(sdp));
  }, []);

  const addIceCandidate = useCallback(async (candidate) => {
    const pc = pcRef.current;
    if (!pc) return;
    try {
      await pc.addIceCandidate(new RTCIceCandidate(candidate));
    } catch (error) {
      console.error('Failed to add ICE candidate:', error);
    }
  }, []);

  const onIceCandidate = useCallback((callback) => {
    const pc = pcRef.current;
    if (!pc) return;
    pc.onicecandidate = (event) => {
      if (event.candidate) {
        callback(event.candidate);
      }
    };
  }, []);

  const toggleAudio = useCallback((muted) => {
    if (localStream) {
      localStream.getAudioTracks().forEach((track) => {
        track.enabled = !muted;
      });
    }
  }, [localStream]);

  const toggleVideo = useCallback((muted) => {
    if (localStream) {
      localStream.getVideoTracks().forEach((track) => {
        track.enabled = !muted;
      });
    }
  }, [localStream]);

  const closeConnection = useCallback(() => {
    if (pcRef.current) {
      pcRef.current.close();
      pcRef.current = null;
    }
    if (localStream) {
      localStream.getTracks().forEach((track) => track.stop());
      setLocalStream(null);
    }
    setRemoteStream(null);
    setConnectionState('closed');
  }, [localStream]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      if (pcRef.current) pcRef.current.close();
      if (localStream) {
        localStream.getTracks().forEach((track) => track.stop());
      }
    };
  // eslint-disable-next-line
  }, []);

  return {
    localStream,
    remoteStream,
    connectionState,
    createPeerConnection,
    startLocalStream,
    addLocalStreamToPeer,
    createOffer,
    createAnswer,
    setRemoteDescription,
    addIceCandidate,
    onIceCandidate,
    toggleAudio,
    toggleVideo,
    closeConnection,
  };
};

export default useWebRTC;
