import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import useWebRTC from '../hooks/useWebRTC';
import {
  connectCallSocket, sendToPeer, onOffer, onAnswer,
  onCandidate, onCancelCall, emitCallStatus,
} from '../api/callSocket';
import { NODE_API } from '../api/config';
import './Calls.css';

const Calls = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { user } = useSelector((state) => state.auth);

  // Call params from URL
  const recipientId = searchParams.get('recipientId');
  const recipientName = searchParams.get('name') || 'User';
  const recipientImage = searchParams.get('image');
  const callType = searchParams.get('type') || 'video'; // video or audio
  const whoCall = searchParams.get('who') || 'sender'; // sender or receiver
  const channelName = searchParams.get('channel') || `call_${user?._id}_${recipientId}_${Date.now()}`;

  const [callState, setCallState] = useState('connecting'); // connecting, ringing, connected, ended
  const [timer, setTimer] = useState(0);
  const [audioMuted, setAudioMuted] = useState(false);
  const [videoMuted, setVideoMuted] = useState(false);
  const [speakerOn, setSpeakerOn] = useState(callType === 'video');
  const timerRef = useRef(null);

  const localVideoRef = useRef(null);
  const remoteVideoRef = useRef(null);

  const {
    localStream, remoteStream, connectionState,
    createPeerConnection, startLocalStream, addLocalStreamToPeer,
    createOffer, createAnswer, setRemoteDescription,
    addIceCandidate, onIceCandidate, toggleAudio, toggleVideo,
    closeConnection,
  } = useWebRTC();

  // Set video elements when streams change
  useEffect(() => {
    if (localVideoRef.current && localStream) {
      localVideoRef.current.srcObject = localStream;
    }
  }, [localStream]);

  useEffect(() => {
    if (remoteVideoRef.current && remoteStream) {
      remoteVideoRef.current.srcObject = remoteStream;
    }
  }, [remoteStream]);

  // Timer for connected call
  useEffect(() => {
    if (callState === 'connected') {
      timerRef.current = setInterval(() => setTimer((t) => t + 1), 1000);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [callState]);

  // Format timer
  const formatTimer = (secs) => {
    const m = Math.floor(secs / 60).toString().padStart(2, '0');
    const s = (secs % 60).toString().padStart(2, '0');
    return `${m}:${s}`;
  };

  // Initialize call
  const initCall = useCallback(async () => {
    try {
      const socket = connectCallSocket();
      const pc = createPeerConnection();
      const stream = await startLocalStream(callType);
      addLocalStreamToPeer(stream);

      // Handle ICE candidates
      onIceCandidate((candidate) => {
        sendToPeer('candidate', candidate, callType,
          user?.fullName || '', recipientName,
          user?._id || '', recipientId
        );
      });

      // Listen for answer (sender)
      onAnswer(async (sdp) => {
        await setRemoteDescription(sdp);
        setCallState('connected');
      });

      // Listen for offer (receiver)
      onOffer(async (sdp) => {
        await setRemoteDescription(sdp);
        const answer = await createAnswer();
        sendToPeer('createAnswer', answer, callType,
          user?.fullName || '', recipientName,
          user?._id || '', recipientId
        );
        setCallState('connected');
      });

      // Listen for ICE candidates from peer
      onCandidate(async (candidate) => {
        await addIceCandidate(candidate);
      });

      // Listen for call cancel
      onCancelCall(() => {
        handleEndCall();
      });

      if (whoCall === 'sender') {
        // Create offer and send
        setCallState('ringing');
        emitCallStatus(user?._id, recipientId, '1', channelName);

        // Wait a moment then create offer
        setTimeout(async () => {
          const offer = await createOffer();
          sendToPeer('createOffer', offer, callType,
            user?.fullName || '', recipientName,
            user?._id || '', recipientId
          );
        }, 1000);
      } else {
        // Receiver — accept and wait for offer
        setCallState('connecting');
        emitCallStatus(user?._id, recipientId, '2', channelName);
      }
    } catch (error) {
      console.error('Call init failed:', error);
      setCallState('ended');
    }
  }, [callType, whoCall, recipientId, recipientName, channelName, user,
    createPeerConnection, startLocalStream, addLocalStreamToPeer,
    createOffer, createAnswer, setRemoteDescription, addIceCandidate,
    onIceCandidate]);

  useEffect(() => {
    if (recipientId) {
      initCall();
    }
    return () => {
      closeConnection();
    };
  // eslint-disable-next-line
  }, []);

  const handleEndCall = useCallback(() => {
    emitCallStatus(user?._id, recipientId, '5', channelName);
    closeConnection();
    setCallState('ended');
    if (timerRef.current) clearInterval(timerRef.current);
    setTimeout(() => navigate(-1), 500);
  }, [user?._id, recipientId, channelName, closeConnection, navigate]);

  const handleToggleAudio = () => {
    const newMuted = !audioMuted;
    setAudioMuted(newMuted);
    toggleAudio(newMuted);
  };

  const handleToggleVideo = () => {
    const newMuted = !videoMuted;
    setVideoMuted(newMuted);
    toggleVideo(newMuted);
  };

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const avatarUrl = getImageUrl(recipientImage);

  return (
    <div className="call-page">
      {/* Remote video (full screen) */}
      {callType === 'video' && (
        <video
          ref={remoteVideoRef}
          className="call-remote-video"
          autoPlay
          playsInline
        />
      )}

      {/* Audio call or no remote video — show avatar */}
      {(callType === 'audio' || !remoteStream) && (
        <div className="call-avatar-screen">
          {avatarUrl ? (
            <img src={avatarUrl} alt="" className="call-avatar-large" />
          ) : (
            <div className="call-avatar-large-placeholder">
              {recipientName[0]?.toUpperCase() || 'U'}
            </div>
          )}
        </div>
      )}

      {/* Local video (small overlay) */}
      {callType === 'video' && localStream && (
        <video
          ref={localVideoRef}
          className="call-local-video"
          autoPlay
          playsInline
          muted
        />
      )}

      {/* Call info */}
      <div className="call-info-overlay">
        <span className="call-recipient-name">{recipientName}</span>
        {callState === 'ringing' && (
          <span className="call-status-text">Ringing...</span>
        )}
        {callState === 'connecting' && (
          <span className="call-status-text">Connecting...</span>
        )}
        {callState === 'connected' && (
          <span className="call-timer">{formatTimer(timer)}</span>
        )}
        {callState === 'ended' && (
          <span className="call-status-text">Call Ended</span>
        )}
      </div>

      {/* Controls */}
      <div className="call-controls">
        <button
          className={`call-control-btn ${audioMuted ? 'active' : ''}`}
          onClick={handleToggleAudio}
          title={audioMuted ? 'Unmute' : 'Mute'}
        >
          {audioMuted ? '🔇' : '🎤'}
        </button>

        {callType === 'video' && (
          <button
            className={`call-control-btn ${videoMuted ? 'active' : ''}`}
            onClick={handleToggleVideo}
            title={videoMuted ? 'Turn on camera' : 'Turn off camera'}
          >
            {videoMuted ? '📷' : '📹'}
          </button>
        )}

        <button
          className="call-control-btn call-end-btn"
          onClick={handleEndCall}
          title="End call"
        >
          📞
        </button>
      </div>
    </div>
  );
};

export default Calls;
